1	/* lexer.h -- PL/SW lexer for COR24 compiler */
2	/* Scans input buffer producing tokens */
3	
4	#ifndef LEXER_H
5	#define LEXER_H
6	
7	#include "token.h"
8	
9	/* Lexer state */
10	char *lex_src;    /* source buffer pointer */
11	int   lex_pos;    /* current position in source */
12	int   lex_len;    /* length of source */
13	
14	/* ---- %INCLUDE processing ---- */
15	
16	#define INC_MAX_DEPTH  4    /* max nesting depth */
17	#define INC_MAX_FILES  16   /* max registered include files */
18	
19	/* Registered include files (name -> content) */
20	char *inc_names[INC_MAX_FILES];
21	char *inc_contents[INC_MAX_FILES];
22	int   inc_count;
23	
24	/* Lexer state stack for nested includes */
25	char *inc_src_stack[INC_MAX_DEPTH];
26	int   inc_pos_stack[INC_MAX_DEPTH];
27	int   inc_len_stack[INC_MAX_DEPTH];
28	int   inc_depth;
29	
30	void inc_init(void) {
31	    inc_count = 0;
32	    inc_depth = 0;
33	}
34	
35	/* Register an include file by name and content */
36	void inc_register(char *name, char *content) {
37	    if (inc_count < INC_MAX_FILES) {
38	        inc_names[inc_count] = name;
39	        inc_contents[inc_count] = content;
40	        inc_count = inc_count + 1;
41	    }
42	}
43	
44	/* Look up include file content by name */
45	char *inc_lookup(char *name) {
46	    int i = 0;
47	    while (i < inc_count) {
48	        if (str_eq_nocase(name, inc_names[i])) {
49	            return inc_contents[i];
50	        }
51	        i = i + 1;
52	    }
53	    return 0;
54	}
55	
56	/* Push current lexer state, switch to include content */
57	int inc_push(char *content) {
58	    if (inc_depth >= INC_MAX_DEPTH) {
59	        return 0;
60	    }
61	    inc_src_stack[inc_depth] = lex_src;
62	    inc_pos_stack[inc_depth] = lex_pos;
63	    inc_len_stack[inc_depth] = lex_len;
64	    inc_depth = inc_depth + 1;
65	
66	    lex_src = content;
67	    lex_pos = 0;
68	    lex_len = str_len(content);
69	    return 1;
70	}
71	
72	/* Pop back to parent lexer state. Returns 1 if popped, 0 if top level. */
73	int inc_pop(void) {
74	    if (inc_depth <= 0) return 0;
75	    inc_depth = inc_depth - 1;
76	    lex_src = inc_src_stack[inc_depth];
77	    lex_pos = inc_pos_stack[inc_depth];
78	    lex_len = inc_len_stack[inc_depth];
79	    return 1;
80	}
81	
82	/* Current token (globals -- no struct on stack) */
83	int  cur_type;
84	int  cur_ival;
85	char cur_text[TOK_TEXT_MAX];
86	
87	/* Initialize lexer with a source buffer */
88	void lex_init(char *src, int len) {
89	    lex_src = src;
90	    lex_pos = 0;
91	    lex_len = len;
92	    inc_depth = 0;
93	    kw_init();
94	}
95	
96	/* Peek at current character without advancing */
97	int lex_peek(void) {
98	    if (lex_pos >= lex_len) return 0;
99	    return lex_src[lex_pos];
100	}
101	
102	/* Advance and return current character */
103	int lex_advance(void) {
104	    if (lex_pos >= lex_len) return 0;
105	    int c = lex_src[lex_pos];
106	    lex_pos = lex_pos + 1;
107	    return c;
108	}
109	
110	/* Peek at next character (one ahead) */
111	int lex_peek2(void) {
112	    if (lex_pos + 1 >= lex_len) return 0;
113	    return lex_src[lex_pos + 1];
114	}
115	
116	/* Character classification */
117	int is_alpha(int c) {
118	    return (c >= 65 && c <= 90) || (c >= 97 && c <= 122) || c == 95;
119	}
120	
121	int is_digit(int c) {
122	    return c >= 48 && c <= 57;
123	}
124	
125	int is_alnum(int c) {
126	    return is_alpha(c) || is_digit(c);
127	}
128	
129	int is_space(int c) {
130	    return c == 32 || c == 9 || c == 10 || c == 13;
131	}
132	
133	/* Skip whitespace and comments */
134	void lex_skip(void) {
135	    while (lex_pos < lex_len) {
136	        int c = lex_peek();
137	
138	        if (is_space(c)) {
139	            lex_advance();
140	            continue;
141	        }
142	
143	        /* block comment: / * ... * / */
144	        if (c == 47 && lex_peek2() == 42) {
145	            lex_advance();
146	            lex_advance();
147	            while (lex_pos < lex_len) {
148	                if (lex_peek() == 42 && lex_peek2() == 47) {
149	                    lex_advance();
150	                    lex_advance();
151	                    break;
152	                }
153	                lex_advance();
154	            }
155	            continue;
156	        }
157	
158	        break;
159	    }
160	}
161	
162	/* Set current token to a simple operator */
163	void lex_set(int type, char *txt) {
164	    cur_type = type;
165	    cur_ival = 0;
166	    str_copy(cur_text, txt);
167	}
168	
169	/* Try to process a %INCLUDE directive at the current position.
170	   Returns 1 if handled, 0 if not a %INCLUDE. */
171	int lex_try_include(void) {
172	    /* Save position in case this isn't %INCLUDE */
173	    int saved = lex_pos;
174	
175	    /* We're at '%' -- advance past it */
176	    lex_advance();
177	
178	    /* Read directive name */
179	    char dname[16];
180	    int di = 0;
181	    while (lex_pos < lex_len && is_alpha(lex_peek()) && di < 15) {
182	        dname[di] = lex_advance();
183	        di = di + 1;
184	    }
185	    dname[di] = 0;
186	
187	    if (!str_eq_nocase(dname, "INCLUDE")) {
188	        /* Not %INCLUDE -- restore position */
189	        lex_pos = saved;
190	        return 0;
191	    }
192	
193	    /* Skip whitespace after INCLUDE */
194	    while (lex_pos < lex_len && is_space(lex_peek())) {
195	        lex_advance();
196	    }
197	
198	    /* Read the include name (until ; or whitespace) */
199	    char iname[TOK_TEXT_MAX];
200	    int ni = 0;
201	    while (lex_pos < lex_len && lex_peek() != 59 && !is_space(lex_peek())
202	           && ni < TOK_TEXT_MAX - 1) {
203	        iname[ni] = lex_advance();
204	        ni = ni + 1;
205	    }
206	    iname[ni] = 0;
207	
208	    /* Skip whitespace and consume trailing semicolon */
209	    while (lex_pos < lex_len && is_space(lex_peek())) {
210	        lex_advance();
211	    }
212	    if (lex_pos < lex_len && lex_peek() == 59) {
213	        lex_advance();
214	    }
215	
216	    /* Look up the include file */
217	    char *content = inc_lookup(iname);
218	    if (!content) {
219	        /* Try with .msw extension */
220	        char fname[TOK_TEXT_MAX];
221	        str_copy(fname, iname);
222	        int flen = str_len(fname);
223	        if (flen + 4 < TOK_TEXT_MAX) {
224	            fname[flen] = 46;     /* . */
225	            fname[flen+1] = 109;  /* m */
226	            fname[flen+2] = 115;  /* s */
227	            fname[flen+3] = 119;  /* w */
228	            fname[flen+4] = 0;
229	            content = inc_lookup(fname);
230	        }
231	    }
232	
233	    if (!content) {
234	        /* Include not found -- not an error for now, just skip */
235	        return 1;
236	    }
237	
238	    /* Push current state and switch to include content */
239	    if (!inc_push(content)) {
240	        /* Too deeply nested */
241	        return 1;
242	    }
243	
244	    return 1;
245	}
246	
247	/* Scan the next token. Result stored in cur_type/cur_ival/cur_text. */
248	int lex_scan(void) {
249	    lex_skip();
250	
251	    cur_ival = 0;
252	    cur_text[0] = 0;
253	
254	    /* Handle EOF: pop include stack if inside an include */
255	    if (lex_pos >= lex_len) {
256	        if (inc_pop()) {
257	            /* Resumed parent -- continue scanning */
258	            return lex_scan();
259	        }
260	        cur_type = TOK_EOF;
261	        str_copy(cur_text, "EOF");
262	        return TOK_EOF;
263	    }
264	
265	    int c = lex_peek();
266	
267	    /* Check for %INCLUDE directive */
268	    if (c == 37) { /* % */
269	        if (lex_try_include()) {
270	            /* Directive consumed -- scan next real token */
271	            return lex_scan();
272	        }
273	    }
274	
275	    /* Identifier or keyword */
276	    if (is_alpha(c)) {
277	        int i = 0;
278	        while (lex_pos < lex_len && is_alnum(lex_peek()) && i < TOK_TEXT_MAX - 1) {
279	            cur_text[i] = lex_advance();
280	            i = i + 1;
281	        }
282	        cur_text[i] = 0;
283	        cur_type = kw_lookup(cur_text);
284	        return cur_type;
285	    }
286	
287	    /* Number */
288	    if (is_digit(c)) {
289	        int i = 0;
290	        int val = 0;
291	        while (lex_pos < lex_len && is_digit(lex_peek()) && i < TOK_TEXT_MAX - 1) {
292	            int d = lex_advance();
293	            cur_text[i] = d;
294	            val = val * 10 + (d - 48);
295	            i = i + 1;
296	        }
297	        cur_text[i] = 0;
298	        cur_type = TOK_NUM;
299	        cur_ival = val;
300	        return TOK_NUM;
301	    }
302	
303	    /* String literal (single-quoted) */
304	    if (c == 39) {
305	        lex_advance(); /* skip opening quote */
306	        int i = 0;
307	        while (lex_pos < lex_len && lex_peek() != 39 && i < TOK_TEXT_MAX - 1) {
308	            cur_text[i] = lex_advance();
309	            i = i + 1;
310	        }
311	        cur_text[i] = 0;
312	        if (lex_pos < lex_len && lex_peek() == 39) {
313	            lex_advance(); /* skip closing quote */
314	        }
315	        cur_type = TOK_STRING;
316	        return TOK_STRING;
317	    }
318	
319	    /* Operators and punctuation */
320	    lex_advance(); /* consume the character */
321	
322	    if (c == 43) { lex_set(TOK_PLUS, "+"); return TOK_PLUS; }
323	    if (c == 42) { lex_set(TOK_STAR, "*"); return TOK_STAR; }
324	    if (c == 47) { lex_set(TOK_SLASH, "/"); return TOK_SLASH; }
325	    if (c == 38) { lex_set(TOK_AMP, "&"); return TOK_AMP; }
326	    if (c == 124) { lex_set(TOK_PIPE, "|"); return TOK_PIPE; }
327	    if (c == 94) { lex_set(TOK_CARET, "^"); return TOK_CARET; }
328	    if (c == 126) { lex_set(TOK_TILDE, "~"); return TOK_TILDE; }
329	    if (c == 61) { lex_set(TOK_EQ, "="); return TOK_EQ; }
330	    if (c == 40) { lex_set(TOK_LPAREN, "("); return TOK_LPAREN; }
331	    if (c == 41) { lex_set(TOK_RPAREN, ")"); return TOK_RPAREN; }
332	    if (c == 44) { lex_set(TOK_COMMA, ","); return TOK_COMMA; }
333	    if (c == 59) { lex_set(TOK_SEMI, ";"); return TOK_SEMI; }
334	    if (c == 46) { lex_set(TOK_DOT, "."); return TOK_DOT; }
335	    if (c == 63) { lex_set(TOK_QUESTION, "?"); return TOK_QUESTION; }
336	    if (c == 37) { lex_set(TOK_PERCENT, "%"); return TOK_PERCENT; }
337	    if (c == 58) { lex_set(TOK_COLON, ":"); return TOK_COLON; }
338	
339	    if (c == 45) { /* - */
340	        if (lex_peek() == 62) {
341	            lex_advance();
342	            lex_set(TOK_ARROW, "->");
343	            return TOK_ARROW;
344	        }
345	        lex_set(TOK_MINUS, "-");
346	        return TOK_MINUS;
347	    }
348	    if (c == 33) { /* ! */
349	        if (lex_peek() == 61) {
350	            lex_advance();
351	            lex_set(TOK_NE, "!=");
352	            return TOK_NE;
353	        }
354	        lex_set(TOK_TILDE, "!");
355	        return TOK_TILDE;
356	    }
357	    if (c == 60) { /* < */
358	        if (lex_peek() == 61) {
359	            lex_advance();
360	            lex_set(TOK_LE, "<=");
361	            return TOK_LE;
362	        }
363	        if (lex_peek() == 60) {
364	            lex_advance();
365	            lex_set(TOK_SHL, "<<");
366	            return TOK_SHL;
367	        }
368	        lex_set(TOK_LT, "<");
369	        return TOK_LT;
370	    }
371	    if (c == 62) { /* > */
372	        if (lex_peek() == 61) {
373	            lex_advance();
374	            lex_set(TOK_GE, ">=");
375	            return TOK_GE;
376	        }
377	        if (lex_peek() == 62) {
378	            lex_advance();
379	            lex_set(TOK_SHR, ">>");
380	            return TOK_SHR;
381	        }
382	        lex_set(TOK_GT, ">");
383	        return TOK_GT;
384	    }
385	
386	    /* Unknown character */
387	    cur_text[0] = c;
388	    cur_text[1] = 0;
389	    cur_type = TOK_EOF;
390	    return TOK_EOF;
391	}
392	
393	/* Print the current token for debugging */
394	void tok_print(void) {
395	    uart_putstr("  ");
396	    uart_putstr(tok_name(cur_type));
397	    if (cur_type == TOK_IDENT || cur_type == TOK_STRING) {
398	        uart_putstr("(");
399	        uart_putstr(cur_text);
400	        uart_putstr(")");
401	    } else if (cur_type == TOK_NUM) {
402	        uart_putstr("(");
403	        print_int(cur_ival);
404	        uart_putstr(")");
405	    }
406	    uart_putchar(10);
407	}
408	
409	/* Tokenize a source string and print all tokens */
410	void lex_dump(char *label, char *src) {
411	    uart_putstr("--- ");
412	    uart_putstr(label);
413	    uart_puts(" ---");
414	
415	    lex_init(src, str_len(src));
416	    while (1) {
417	        lex_scan();
418	        tok_print();
419	        if (cur_type == TOK_EOF) break;
420	    }
421	}
422	
423	#endif
