/* macro.h -- Macro definition table and MACRODEF parser for PL/SW */
/* Parses MACRODEF name; clauses; body; END; from .msw files */

#ifndef MACRO_H
#define MACRO_H

#include "token.h"
#include "arena.h"

/* ---- Clause parameter types ---- */
#define MCLAUSE_EXPR    1   /* expression argument */
#define MCLAUSE_LVALUE  2   /* lvalue (assignable) argument */
#define MCLAUSE_LABEL   3   /* label or block argument */

/* ---- Clause requirement ---- */
#define MCLAUSE_REQUIRED 1
#define MCLAUSE_OPTIONAL 2

/* ---- Limits ---- */
#define MACRO_MAX       16   /* max macro definitions */
#define MACRO_CLAUSE_MAX 8   /* max clauses per macro */
#define MACRO_NAME_MAX  32   /* max macro/clause name length */
#define MACRO_BODY_MAX  512  /* max body text per macro */
#define MACRO_GEN_MAX   4    /* max GEN blocks per macro */
#define MACRO_GEN_LINE  128  /* max chars per GEN template string */
#define MACRO_GEN_LINES 16   /* max lines per GEN block */

/* ---- Clause definition ---- */
/* Parallel arrays per macro, indexed by clause index */

/* ---- GEN block ---- */
/* Stores template strings from GEN DO; "str"; ... END; */

/* ---- Macro table ---- */
/* Parallel arrays indexed by macro index */

char  mac_names[MACRO_MAX][MACRO_NAME_MAX];
int   mac_count;

/* Clause data -- mac_cl_* arrays are [MACRO_MAX][MACRO_CLAUSE_MAX] */
char  mac_cl_names[MACRO_MAX * MACRO_CLAUSE_MAX][MACRO_NAME_MAX];
int   mac_cl_types[MACRO_MAX * MACRO_CLAUSE_MAX];   /* MCLAUSE_EXPR/LVALUE/LABEL */
int   mac_cl_req[MACRO_MAX * MACRO_CLAUSE_MAX];      /* MCLAUSE_REQUIRED/OPTIONAL */
int   mac_cl_count[MACRO_MAX];                        /* clause count per macro */

/* GEN block data -- template strings */
char  mac_gen_lines[MACRO_MAX * MACRO_GEN_MAX * MACRO_GEN_LINES][MACRO_GEN_LINE];
int   mac_gen_lcount[MACRO_MAX * MACRO_GEN_MAX];     /* line count per GEN block */
int   mac_gen_count[MACRO_MAX];                       /* GEN block count per macro */

/* Body text (non-GEN PL/SW statements between clauses and END) */
char  mac_body[MACRO_MAX][MACRO_BODY_MAX];

void mac_init(void) {
    mac_count = 0;
    int i = 0;
    while (i < MACRO_MAX) {
        mac_names[i][0] = 0;
        mac_cl_count[i] = 0;
        mac_gen_count[i] = 0;
        mac_body[i][0] = 0;
        i = i + 1;
    }
}

/* Index helper for clause arrays: macro_idx * MACRO_CLAUSE_MAX + clause_idx */
int mac_cl_idx(int mi, int ci) {
    return mi * MACRO_CLAUSE_MAX + ci;
}

/* Index helper for GEN line arrays */
int mac_gen_line_idx(int mi, int gi, int li) {
    return (mi * MACRO_GEN_MAX + gi) * MACRO_GEN_LINES + li;
}

/* Index helper for GEN block line count */
int mac_gen_lcount_idx(int mi, int gi) {
    return mi * MACRO_GEN_MAX + gi;
}

/* Look up a macro by name. Returns index or -1. */
int mac_lookup(char *name) {
    int i = 0;
    while (i < mac_count) {
        if (str_eq_nocase(name, mac_names[i])) {
            return i;
        }
        i = i + 1;
    }
    return -1;
}

/* ---- MACRODEF parser ---- */
/* Uses the lexer globals (cur_type, cur_text, lex_scan) */

int mac_parse_err;
char mac_parse_errmsg[128];

void mac_error(char *msg) {
    mac_parse_err = 1;
    str_ncopy(mac_parse_errmsg, msg, 128);
}

/* Expect and consume a specific token type. Returns 1 on success. */
int mac_expect(int ttype) {
    if (cur_type != ttype) {
        mac_error("unexpected token in MACRODEF");
        return 0;
    }
    lex_scan();
    return 1;
}

/* Parse clause type keyword: expr, lvalue, label */
int mac_parse_clause_type(void) {
    if (cur_type == TOK_IDENT) {
        if (str_eq_nocase(cur_text, "expr")) {
            lex_scan();
            return MCLAUSE_EXPR;
        }
        if (str_eq_nocase(cur_text, "lvalue")) {
            lex_scan();
            return MCLAUSE_LVALUE;
        }
        if (str_eq_nocase(cur_text, "label")) {
            lex_scan();
            return MCLAUSE_LABEL;
        }
    }
    /* Default to expr if unrecognized */
    if (cur_type == TOK_IDENT) lex_scan();
    return MCLAUSE_EXPR;
}

/* Parse a single clause: REQUIRED/OPTIONAL NAME(type); */
int mac_parse_clause(int mi) {
    int ci = mac_cl_count[mi];
    if (ci >= MACRO_CLAUSE_MAX) {
        mac_error("too many clauses in MACRODEF");
        return 0;
    }

    int idx = mac_cl_idx(mi, ci);

    /* REQUIRED or OPTIONAL */
    if (cur_type == TOK_IDENT && str_eq_nocase(cur_text, "REQUIRED")) {
        mac_cl_req[idx] = MCLAUSE_REQUIRED;
        lex_scan();
    } else if (cur_type == TOK_IDENT && str_eq_nocase(cur_text, "OPTIONAL")) {
        mac_cl_req[idx] = MCLAUSE_OPTIONAL;
        lex_scan();
    } else {
        return 0; /* not a clause */
    }

    /* Clause name */
    if (cur_type != TOK_IDENT) {
        mac_error("expected clause name");
        return 0;
    }
    str_ncopy(mac_cl_names[idx], cur_text, MACRO_NAME_MAX);
    lex_scan();

    /* (type) */
    if (!mac_expect(TOK_LPAREN)) return 0;
    mac_cl_types[idx] = mac_parse_clause_type();
    if (!mac_expect(TOK_RPAREN)) return 0;

    /* Semicolon */
    if (!mac_expect(TOK_SEMI)) return 0;

    mac_cl_count[mi] = ci + 1;
    return 1;
}

/* Parse a GEN DO; "str"; ... END; block */
int mac_parse_gen(int mi) {
    int gi = mac_gen_count[mi];
    if (gi >= MACRO_GEN_MAX) {
        mac_error("too many GEN blocks");
        return 0;
    }

    /* We're at GEN -- expect GEN DO ; */
    /* GEN is an IDENT "GEN" */
    lex_scan(); /* skip GEN */

    if (cur_type != TOK_DO) {
        mac_error("expected DO after GEN");
        return 0;
    }
    lex_scan(); /* skip DO */

    if (!mac_expect(TOK_SEMI)) return 0;

    /* Parse template strings until END */
    int lcount = 0;
    int lc_idx = mac_gen_lcount_idx(mi, gi);

    while (cur_type != TOK_END && cur_type != TOK_EOF && !mac_parse_err) {
        if (cur_type == TOK_STRING) {
            if (lcount < MACRO_GEN_LINES) {
                int line_idx = mac_gen_line_idx(mi, gi, lcount);
                str_ncopy(mac_gen_lines[line_idx], cur_text, MACRO_GEN_LINE);
                lcount = lcount + 1;
            }
            lex_scan();
        } else {
            /* Skip non-string tokens in GEN block */
            lex_scan();
        }
        /* Consume optional semicolons between strings */
        while (cur_type == TOK_SEMI) {
            lex_scan();
        }
    }

    mac_gen_lcount[lc_idx] = lcount;

    /* Consume END ; */
    if (cur_type == TOK_END) {
        lex_scan();
    }
    if (cur_type == TOK_SEMI) {
        lex_scan();
    }

    mac_gen_count[mi] = gi + 1;
    return 1;
}

/* Collect remaining body text (IF/THEN/ELSE blocks etc.) until END */
void mac_parse_body(int mi) {
    int pos = 0;
    int depth = 0; /* track nested DO/END */

    while (cur_type != TOK_EOF && !mac_parse_err) {
        /* Check for final END (depth == 0) */
        if (cur_type == TOK_END && depth == 0) {
            break;
        }

        /* Track nesting */
        if (cur_type == TOK_DO) {
            depth = depth + 1;
        }
        if (cur_type == TOK_END) {
            depth = depth - 1;
        }

        /* Append token text to body */
        if (pos > 0 && pos < MACRO_BODY_MAX - 2) {
            mac_body[mi][pos] = 32; /* space */
            pos = pos + 1;
        }

        int tlen = str_len(cur_text);
        if (pos + tlen < MACRO_BODY_MAX - 1) {
            str_copy(mac_body[mi] + pos, cur_text);
            pos = pos + tlen;
        }

        lex_scan();
    }

    mac_body[mi][pos] = 0;
}

/* Parse a complete MACRODEF: MACRODEF name; clauses; [GEN; body;] END;
   Assumes lexer is positioned at "MACRODEF" (an IDENT token).
   Returns macro index or -1 on error. */
int mac_parse_def(void) {
    mac_parse_err = 0;
    mac_parse_errmsg[0] = 0;

    if (mac_count >= MACRO_MAX) {
        mac_error("too many macro definitions");
        return -1;
    }

    int mi = mac_count;

