    mac_cl_count[mi] = 0;
    mac_gen_count[mi] = 0;
    mac_body[mi][0] = 0;

    /* Parse clauses (REQUIRED/OPTIONAL) */
    while (!mac_parse_err && cur_type != TOK_EOF) {
        /* Check if this is a clause */
        if (cur_type == TOK_IDENT &&
            (str_eq_nocase(cur_text, "REQUIRED") ||
             str_eq_nocase(cur_text, "OPTIONAL"))) {
            if (!mac_parse_clause(mi)) break;
            continue;
        }
        break;
    }

    if (mac_parse_err) return -1;

    /* Parse GEN blocks and body until END */
    while (cur_type != TOK_END && cur_type != TOK_EOF && !mac_parse_err) {
        if (cur_type == TOK_IDENT && str_eq_nocase(cur_text, "GEN")) {
            mac_parse_gen(mi);
            continue;
        }
        /* Remaining body text */
        mac_parse_body(mi);
    }

    if (mac_parse_err) return -1;

    /* Consume final END ; */
    if (cur_type == TOK_END) {
        lex_scan();
    } else {
        mac_error("expected END for MACRODEF");
        return -1;
    }
    if (cur_type == TOK_SEMI) {
        lex_scan();
    }

    mac_count = mi + 1;
    return mi;
}

/* Parse all MACRODEFs from current lexer input (an .msw file).
   Skips non-MACRODEF content. Returns number parsed. */
int mac_parse_file(void) {
    int count = 0;
    while (cur_type != TOK_EOF && !mac_parse_err) {
