    uart_putstr("insert COUNT (shadow): idx=");
    print_int(idx);
    uart_putchar(10);

    /* Lookup should find the inner (shadowed) one */
    idx = sym_lookup("COUNT");
    uart_putstr("lookup COUNT (should be inner): idx=");
    print_int(idx);
    uart_putstr(" type=");
    uart_puts(nd_type_name(sym_type[idx]));

