    cg_static_init();

    parse_init("PROC CLAMP(X INT(24), LO INT(24), HI INT(24)) RETURNS(INT(24)); IF X < LO THEN DO; X = LO; RETURN(X); END; ELSE DO; IF X > HI THEN X = HI; RETURN(X); END; END;");
    prog = parse_program();
    if (parse_err) {
        uart_putstr("  PARSE ERROR: ");
        uart_puts(parse_errmsg);
        errs = errs + 1;
