        if (!str_find(out, "L0:")) {
            uart_puts("  FAIL: missing label L0");
            errs = errs + 1;
        }
        /* At least 3 labels for outer if/else + inner if */
        if (!str_find(out, "L2:")) {
            uart_puts("  FAIL: missing label L2 (nested if needs labels)");
            errs = errs + 1;
        }
