        if (!str_find(out, "add     r0,r1")) {
            uart_puts("  FAIL: missing add r0,r1 for pointer arithmetic");
            errs = errs + 1;
        }
        /* ADDR: add r0,fp */
        if (!str_find(out, "add     r0,fp")) {
            uart_puts("  FAIL: missing add r0,fp for ADDR(X)");
            errs = errs + 1;
        }
    }

    /* Summary */
