void test_macro_def(void) {
    int errs;
    int mi;

    errs = 0;

    /* Test 1: Parse GETMAIN macro with REQUIRED/OPTIONAL clauses and GEN block */
    uart_puts("--- macrodef: GETMAIN ---");
    mac_init();

    char *getmain_src =
        "MACRODEF GETMAIN;"
        "   REQUIRED LENGTH(expr);"
        "   OPTIONAL SUBPOOL(expr);"
        "   OPTIONAL ADDRESS(lvalue);"
        "   OPTIONAL RC(lvalue);"
        "   GEN DO;"
        "      'mvi r0,{LENGTH}';"
        "      'svc 10';"
        "   END;"
        "END;";

    lex_init(getmain_src, str_len(getmain_src));
    lex_scan();
    mi = mac_parse_def();

    if (mac_parse_err) {
        uart_putstr("  PARSE ERROR: ");
        uart_puts(mac_parse_errmsg);
        errs = errs + 1;
    } else if (mi < 0) {
        uart_puts("  FAIL: mac_parse_def returned -1");
        errs = errs + 1;
    } else {
        /* Verify macro name */
        if (!str_eq_nocase(mac_names[mi], "GETMAIN")) {
            uart_puts("  FAIL: name != GETMAIN");
            errs = errs + 1;
        } else {
            uart_puts("  OK: name = GETMAIN");
        }

        /* Verify clause count */
        if (mac_cl_count[mi] != 4) {
            uart_putstr("  FAIL: clause count = ");
            print_int(mac_cl_count[mi]);
            uart_puts(" (expected 4)");
            errs = errs + 1;
        } else {
            uart_puts("  OK: 4 clauses");
        }

        /* Verify first clause: REQUIRED LENGTH(expr) */
        int idx0 = mac_cl_idx(mi, 0);
        if (mac_cl_req[idx0] != MCLAUSE_REQUIRED) {
            uart_puts("  FAIL: clause 0 not REQUIRED");
            errs = errs + 1;
        }
        if (!str_eq_nocase(mac_cl_names[idx0], "LENGTH")) {
            uart_puts("  FAIL: clause 0 name != LENGTH");
            errs = errs + 1;
        }
        if (mac_cl_types[idx0] != MCLAUSE_EXPR) {
            uart_puts("  FAIL: clause 0 type != expr");
            errs = errs + 1;
        }
        if (mac_cl_req[idx0] == MCLAUSE_REQUIRED &&
            str_eq_nocase(mac_cl_names[idx0], "LENGTH") &&
            mac_cl_types[idx0] == MCLAUSE_EXPR) {
