    /* Test 9: record as local variable */
    uart_puts("--- record local ---");
    arena_init();
    ast_init();
    sym_init();
    types_init();
    layout_init();

    parse_init("PROC SETUP; DCL 1 PT, 3 X INT(24), 3 Y INT(24); DCL Z INT(24); RETURN; END;");
