        idx = sym_lookup("PT");
        if (idx >= 0) {
            uart_putstr("  PT(record): offset=");
            print_int(sym_offset[idx]);
            uart_putstr(" width=");
            print_int(sym_width[idx]);
            uart_putchar(10);
        }

        idx = sym_lookup("Z");
        uart_putstr("  Z(auto): offset=");
        print_int(sym_offset[idx]);
        uart_putchar(10);

        sym_exit_scope();
    } else {
        uart_puts("  PARSE ERROR");
    }

    /* Test 10: empty procedure (no params, no locals) */
    uart_puts("--- empty proc ---");
    arena_init();
    ast_init();
    sym_init();
    types_init();
    layout_init();

