        uart_puts(parse_errmsg);
        errs = errs + 1;
    } else {
        cg_program_procs(prog);
        out = emit_output();
        uart_putstr(out);
        /* 3 args = 9 bytes stack space */
        if (!str_find(out, "lc      r2,9")) {
            uart_puts("  FAIL: missing 9-byte stack alloc");
