/* ========== Pointer Codegen Tests ========== */

void test_pointer_codegen(void) {
    int errs;
    int prog;
    char *out;

    errs = 0;

    /* Test 1: ADDR of a local variable */
    uart_puts("--- pointer: ADDR of local var ---");
    arena_init();
    ast_init();
    sym_init();
    types_init();
    layout_init();
    emit_init();
    cg_init();
    cg_static_init();

    parse_init("PROC TEST(); DCL X INT(24); DCL P PTR; X = 42; P = ADDR(X); END;");
