        uart_putstr(out);

        if (!str_find(out, "_TEST:")) {
            uart_puts("  FAIL: missing proc label _TEST");
            errs = errs + 1;
        }
        /* ADDR computes fp + offset: add r0,fp */
        if (!str_find(out, "add     r0,fp")) {
