1	/* macro.h -- Macro definition table and MACRODEF parser for PL/SW */
2	/* Parses MACRODEF name; clauses; body; END; from .msw files */
3	
4	#ifndef MACRO_H
5	#define MACRO_H
6	
7	#include "token.h"
8	#include "arena.h"
9	
10	/* ---- Clause parameter types ---- */
11	#define MCLAUSE_EXPR    1   /* expression argument */
12	#define MCLAUSE_LVALUE  2   /* lvalue (assignable) argument */
13	#define MCLAUSE_LABEL   3   /* label or block argument */
14	
15	/* ---- Clause requirement ---- */
16	#define MCLAUSE_REQUIRED 1
17	#define MCLAUSE_OPTIONAL 2
18	
19	/* ---- Limits ---- */
20	#define MACRO_MAX       16   /* max macro definitions */
21	#define MACRO_CLAUSE_MAX 8   /* max clauses per macro */
22	#define MACRO_NAME_MAX  32   /* max macro/clause name length */
23	#define MACRO_BODY_MAX  512  /* max body text per macro */
24	#define MACRO_GEN_MAX   4    /* max GEN blocks per macro */
25	#define MACRO_GEN_LINE  128  /* max chars per GEN template string */
26	#define MACRO_GEN_LINES 16   /* max lines per GEN block */
27	
28	/* ---- Clause definition ---- */
29	/* Parallel arrays per macro, indexed by clause index */
30	
31	/* ---- GEN block ---- */
32	/* Stores template strings from GEN DO; "str"; ... END; */
33	
34	/* ---- Macro table ---- */
35	/* Parallel arrays indexed by macro index */
36	
37	char  mac_names[MACRO_MAX][MACRO_NAME_MAX];
38	int   mac_count;
39	
40	/* Clause data -- mac_cl_* arrays are [MACRO_MAX][MACRO_CLAUSE_MAX] */
41	char  mac_cl_names[MACRO_MAX * MACRO_CLAUSE_MAX][MACRO_NAME_MAX];
42	int   mac_cl_types[MACRO_MAX * MACRO_CLAUSE_MAX];   /* MCLAUSE_EXPR/LVALUE/LABEL */
43	int   mac_cl_req[MACRO_MAX * MACRO_CLAUSE_MAX];      /* MCLAUSE_REQUIRED/OPTIONAL */
44	int   mac_cl_count[MACRO_MAX];                        /* clause count per macro */
45	
46	/* GEN block data -- template strings */
47	char  mac_gen_lines[MACRO_MAX * MACRO_GEN_MAX * MACRO_GEN_LINES][MACRO_GEN_LINE];
48	int   mac_gen_lcount[MACRO_MAX * MACRO_GEN_MAX];     /* line count per GEN block */
49	int   mac_gen_count[MACRO_MAX];                       /* GEN block count per macro */
50	
51	/* Body text (non-GEN PL/SW statements between clauses and END) */
52	char  mac_body[MACRO_MAX][MACRO_BODY_MAX];
53	
54	void mac_init(void) {
55	    mac_count = 0;
56	    int i = 0;
57	    while (i < MACRO_MAX) {
58	        mac_names[i][0] = 0;
59	        mac_cl_count[i] = 0;
60	        mac_gen_count[i] = 0;
61	        mac_body[i][0] = 0;
62	        i = i + 1;
63	    }
64	}
65	
66	/* Index helper for clause arrays: macro_idx * MACRO_CLAUSE_MAX + clause_idx */
67	int mac_cl_idx(int mi, int ci) {
68	    return mi * MACRO_CLAUSE_MAX + ci;
69	}
70	
71	/* Index helper for GEN line arrays */
72	int mac_gen_line_idx(int mi, int gi, int li) {
73	    return (mi * MACRO_GEN_MAX + gi) * MACRO_GEN_LINES + li;
74	}
75	
76	/* Index helper for GEN block line count */
77	int mac_gen_lcount_idx(int mi, int gi) {
78	    return mi * MACRO_GEN_MAX + gi;
79	}
80	
81	/* Look up a macro by name. Returns index or -1. */
82	int mac_lookup(char *name) {
83	    int i = 0;
84	    while (i < mac_count) {
85	        if (str_eq_nocase(name, mac_names[i])) {
86	            return i;
87	        }
88	        i = i + 1;
89	    }
90	    return -1;
91	}
92	
93	/* ---- MACRODEF parser ---- */
94	/* Uses the lexer globals (cur_type, cur_text, lex_scan) */
95	
96	int mac_parse_err;
97	char mac_parse_errmsg[128];
98	
99	void mac_error(char *msg) {
100	    mac_parse_err = 1;
101	    str_ncopy(mac_parse_errmsg, msg, 128);
102	}
103	
104	/* Expect and consume a specific token type. Returns 1 on success. */
105	int mac_expect(int ttype) {
106	    if (cur_type != ttype) {
107	        mac_error("unexpected token in MACRODEF");
108	        return 0;
109	    }
110	    lex_scan();
111	    return 1;
112	}
113	
114	/* Parse clause type keyword: expr, lvalue, label */
115	int mac_parse_clause_type(void) {
116	    if (cur_type == TOK_IDENT) {
117	        if (str_eq_nocase(cur_text, "expr")) {
118	            lex_scan();
119	            return MCLAUSE_EXPR;
120	        }
121	        if (str_eq_nocase(cur_text, "lvalue")) {
122	            lex_scan();
123	            return MCLAUSE_LVALUE;
124	        }
125	        if (str_eq_nocase(cur_text, "label")) {
126	            lex_scan();
127	            return MCLAUSE_LABEL;
128	        }
129	    }
130	    /* Default to expr if unrecognized */
131	    if (cur_type == TOK_IDENT) lex_scan();
132	    return MCLAUSE_EXPR;
133	}
134	
135	/* Parse a single clause: REQUIRED/OPTIONAL NAME(type); */
136	int mac_parse_clause(int mi) {
137	    int ci = mac_cl_count[mi];
138	    if (ci >= MACRO_CLAUSE_MAX) {
139	        mac_error("too many clauses in MACRODEF");
140	        return 0;
141	    }
142	
143	    int idx = mac_cl_idx(mi, ci);
144	
145	    /* REQUIRED or OPTIONAL */
146	    if (cur_type == TOK_IDENT && str_eq_nocase(cur_text, "REQUIRED")) {
147	        mac_cl_req[idx] = MCLAUSE_REQUIRED;
148	        lex_scan();
149	    } else if (cur_type == TOK_IDENT && str_eq_nocase(cur_text, "OPTIONAL")) {
150	        mac_cl_req[idx] = MCLAUSE_OPTIONAL;
151	        lex_scan();
152	    } else {
153	        return 0; /* not a clause */
154	    }
155	
156	    /* Clause name */
157	    if (cur_type != TOK_IDENT) {
158	        mac_error("expected clause name");
159	        return 0;
160	    }
161	    str_ncopy(mac_cl_names[idx], cur_text, MACRO_NAME_MAX);
162	    lex_scan();
163	
164	    /* (type) */
165	    if (!mac_expect(TOK_LPAREN)) return 0;
166	    mac_cl_types[idx] = mac_parse_clause_type();
167	    if (!mac_expect(TOK_RPAREN)) return 0;
168	
169	    /* Semicolon */
170	    if (!mac_expect(TOK_SEMI)) return 0;
171	
172	    mac_cl_count[mi] = ci + 1;
173	    return 1;
174	}
175	
176	/* Parse a GEN DO; "str"; ... END; block */
177	int mac_parse_gen(int mi) {
178	    int gi = mac_gen_count[mi];
179	    if (gi >= MACRO_GEN_MAX) {
180	        mac_error("too many GEN blocks");
181	        return 0;
182	    }
183	
184	    /* We're at GEN -- expect GEN DO ; */
185	    /* GEN is an IDENT "GEN" */
186	    lex_scan(); /* skip GEN */
187	
188	    if (cur_type != TOK_DO) {
189	        mac_error("expected DO after GEN");
190	        return 0;
191	    }
192	    lex_scan(); /* skip DO */
193	
194	    if (!mac_expect(TOK_SEMI)) return 0;
195	
196	    /* Parse template strings until END */
197	    int lcount = 0;
198	    int lc_idx = mac_gen_lcount_idx(mi, gi);
199	
200	    while (cur_type != TOK_END && cur_type != TOK_EOF && !mac_parse_err) {
201	        if (cur_type == TOK_STRING) {
202	            if (lcount < MACRO_GEN_LINES) {
203	                int line_idx = mac_gen_line_idx(mi, gi, lcount);
204	                str_ncopy(mac_gen_lines[line_idx], cur_text, MACRO_GEN_LINE);
205	                lcount = lcount + 1;
206	            }
207	            lex_scan();
208	        } else {
209	            /* Skip non-string tokens in GEN block */
210	            lex_scan();
211	        }
212	        /* Consume optional semicolons between strings */
213	        while (cur_type == TOK_SEMI) {
214	            lex_scan();
215	        }
216	    }
217	
218	    mac_gen_lcount[lc_idx] = lcount;
219	
220	    /* Consume END ; */
221	    if (cur_type == TOK_END) {
222	        lex_scan();
223	    }
224	    if (cur_type == TOK_SEMI) {
225	        lex_scan();
226	    }
227	
228	    mac_gen_count[mi] = gi + 1;
229	    return 1;
230	}
231	
232	/* Collect remaining body text (IF/THEN/ELSE blocks etc.) until END */
233	void mac_parse_body(int mi) {
234	    int pos = 0;
235	    int depth = 0; /* track nested DO/END */
236	
237	    while (cur_type != TOK_EOF && !mac_parse_err) {
238	        /* Check for final END (depth == 0) */
239	        if (cur_type == TOK_END && depth == 0) {
240	            break;
241	        }
242	
243	        /* Track nesting */
244	        if (cur_type == TOK_DO) {
245	            depth = depth + 1;
246	        }
247	        if (cur_type == TOK_END) {
248	            depth = depth - 1;
249	        }
250	
251	        /* Append token text to body */
252	        if (pos > 0 && pos < MACRO_BODY_MAX - 2) {
253	            mac_body[mi][pos] = 32; /* space */
254	            pos = pos + 1;
255	        }
256	
257	        int tlen = str_len(cur_text);
258	        if (pos + tlen < MACRO_BODY_MAX - 1) {
259	            str_copy(mac_body[mi] + pos, cur_text);
260	            pos = pos + tlen;
261	        }
262	
263	        lex_scan();
264	    }
265	
266	    mac_body[mi][pos] = 0;
267	}
268	
269	/* Parse a complete MACRODEF: MACRODEF name; clauses; [GEN; body;] END;
270	   Assumes lexer is positioned at "MACRODEF" (an IDENT token).
271	   Returns macro index or -1 on error. */
272	int mac_parse_def(void) {
273	    mac_parse_err = 0;
274	    mac_parse_errmsg[0] = 0;
275	
276	    if (mac_count >= MACRO_MAX) {
277	        mac_error("too many macro definitions");
278	        return -1;
279	    }
280	
281	    int mi = mac_count;
282	
283	    /* Skip MACRODEF keyword (it's an IDENT) */
284	    lex_scan();
285	
286	    /* Macro name */
287	    if (cur_type != TOK_IDENT) {
288	        mac_error("expected macro name after MACRODEF");
289	        return -1;
290	    }
291	    str_ncopy(mac_names[mi], cur_text, MACRO_NAME_MAX);
292	    lex_scan();
293	
294	    /* Semicolon after name */
295	    if (!mac_expect(TOK_SEMI)) return -1;
296	
297	    /* Initialize this macro's clause/gen counts */
298	    mac_cl_count[mi] = 0;
299	    mac_gen_count[mi] = 0;
300	    mac_body[mi][0] = 0;
301	
302	    /* Parse clauses (REQUIRED/OPTIONAL) */
303	    while (!mac_parse_err && cur_type != TOK_EOF) {
304	        /* Check if this is a clause */
305	        if (cur_type == TOK_IDENT &&
306	            (str_eq_nocase(cur_text, "REQUIRED") ||
307	             str_eq_nocase(cur_text, "OPTIONAL"))) {
308	            if (!mac_parse_clause(mi)) break;
309	            continue;
310	        }
311	        break;
312	    }
313	
314	    if (mac_parse_err) return -1;
315	
316	    /* Parse GEN blocks and body until END */
317	    while (cur_type != TOK_END && cur_type != TOK_EOF && !mac_parse_err) {
318	        if (cur_type == TOK_IDENT && str_eq_nocase(cur_text, "GEN")) {
319	            mac_parse_gen(mi);
320	            continue;
321	        }
322	        /* Remaining body text */
323	        mac_parse_body(mi);
324	    }
325	
326	    if (mac_parse_err) return -1;
327	
328	    /* Consume final END ; */
329	    if (cur_type == TOK_END) {
330	        lex_scan();
331	    } else {
332	        mac_error("expected END for MACRODEF");
333	        return -1;
334	    }
335	    if (cur_type == TOK_SEMI) {
336	        lex_scan();
337	    }
338	
339	    mac_count = mi + 1;
340	    return mi;
341	}
342	
343	/* Parse all MACRODEFs from current lexer input (an .msw file).
344	   Skips non-MACRODEF content. Returns number parsed. */
345	int mac_parse_file(void) {
346	    int count = 0;
347	    while (cur_type != TOK_EOF && !mac_parse_err) {
348	        if (cur_type == TOK_IDENT && str_eq_nocase(cur_text, "MACRODEF")) {
349	            int mi = mac_parse_def();
350	            if (mi >= 0) {
351	                count = count + 1;
352	            } else {
353	                break;
354	            }
355	        } else {
356	            /* Skip non-MACRODEF tokens */
357	            lex_scan();
358	        }
359	    }
360	    return count;
361	}
362	
363	/* Debug: print macro table */
364	void mac_dump(void) {
365	    int i = 0;
366	    uart_putstr("macro table: ");
367	    print_int(mac_count);
368	    uart_puts(" macros");
369	
370	    while (i < mac_count) {
371	        uart_putstr("  MACRODEF ");
372	        uart_puts(mac_names[i]);
373	
374	        /* Clauses */
375	        int ci = 0;
376	        while (ci < mac_cl_count[i]) {
377	            int idx = mac_cl_idx(i, ci);
378	            uart_putstr("    ");
379	            if (mac_cl_req[idx] == MCLAUSE_REQUIRED) {
380	                uart_putstr("REQUIRED ");
381	            } else {
382	                uart_putstr("OPTIONAL ");
383	            }
384	            uart_putstr(mac_cl_names[idx]);
385	            uart_putstr("(");
386	            if (mac_cl_types[idx] == MCLAUSE_EXPR) {
387	                uart_putstr("expr");
388	            } else if (mac_cl_types[idx] == MCLAUSE_LVALUE) {
389	                uart_putstr("lvalue");
390	            } else if (mac_cl_types[idx] == MCLAUSE_LABEL) {
391	                uart_putstr("label");
392	            }
393	            uart_puts(")");
394	            ci = ci + 1;
395	        }
396	
397	        /* GEN blocks */
