void test_macro_def(void) {
    int errs;
    int mi;

    errs = 0;

    /* Test 1: Parse GETMAIN macro with REQUIRED/OPTIONAL clauses and GEN block */
    uart_puts("--- macrodef: GETMAIN ---");
    mac_init();

    char *getmain_src =
        "MACRODEF GETMAIN;"
        "   REQUIRED LENGTH(expr);"
        "   OPTIONAL SUBPOOL(expr);"
        "   OPTIONAL ADDRESS(lvalue);"
        "   OPTIONAL RC(lvalue);"
        "   GEN DO;"
        "      'mvi r0,{LENGTH}';"
        "      'svc 10';"
        "   END;"
        "END;";

    lex_init(getmain_src, str_len(getmain_src));
    lex_scan();
    mi = mac_parse_def();

    if (mac_parse_err) {
        uart_putstr("  PARSE ERROR: ");
        uart_puts(mac_parse_errmsg);
        errs = errs + 1;
    } else if (mi < 0) {
        uart_puts("  FAIL: mac_parse_def returned -1");
        errs = errs + 1;
    } else {
        /* Verify macro name */
        if (!str_eq_nocase(mac_names[mi], "GETMAIN")) {
            uart_puts("  FAIL: name != GETMAIN");
            errs = errs + 1;
        } else {
            uart_puts("  OK: name = GETMAIN");
        }

        /* Verify clause count */
        if (mac_cl_count[mi] != 4) {
            uart_putstr("  FAIL: clause count = ");
            print_int(mac_cl_count[mi]);
            uart_puts(" (expected 4)");
            errs = errs + 1;
        } else {
            uart_puts("  OK: 4 clauses");
        }

        /* Verify first clause: REQUIRED LENGTH(expr) */
        int idx0 = mac_cl_idx(mi, 0);
        if (mac_cl_req[idx0] != MCLAUSE_REQUIRED) {
            uart_puts("  FAIL: clause 0 not REQUIRED");
            errs = errs + 1;
        }
        if (!str_eq_nocase(mac_cl_names[idx0], "LENGTH")) {
            uart_puts("  FAIL: clause 0 name != LENGTH");
            errs = errs + 1;
        }
        if (mac_cl_types[idx0] != MCLAUSE_EXPR) {
            uart_puts("  FAIL: clause 0 type != expr");
            errs = errs + 1;
        }
        if (mac_cl_req[idx0] == MCLAUSE_REQUIRED &&
            str_eq_nocase(mac_cl_names[idx0], "LENGTH") &&
            mac_cl_types[idx0] == MCLAUSE_EXPR) {
            uart_puts("  OK: REQUIRED LENGTH(expr)");
        }

        /* Verify third clause: OPTIONAL ADDRESS(lvalue) */
        int idx2 = mac_cl_idx(mi, 2);
        if (mac_cl_req[idx2] != MCLAUSE_OPTIONAL) {
            uart_puts("  FAIL: clause 2 not OPTIONAL");
            errs = errs + 1;
        }
        if (!str_eq_nocase(mac_cl_names[idx2], "ADDRESS")) {
            uart_puts("  FAIL: clause 2 name != ADDRESS");
            errs = errs + 1;
        }
        if (mac_cl_types[idx2] != MCLAUSE_LVALUE) {
            uart_puts("  FAIL: clause 2 type != lvalue");
            errs = errs + 1;
        }
        if (mac_cl_req[idx2] == MCLAUSE_OPTIONAL &&
            str_eq_nocase(mac_cl_names[idx2], "ADDRESS") &&
            mac_cl_types[idx2] == MCLAUSE_LVALUE) {
            uart_puts("  OK: OPTIONAL ADDRESS(lvalue)");
        }

        /* Verify GEN block */
        if (mac_gen_count[mi] != 1) {
            uart_putstr("  FAIL: gen count = ");
            print_int(mac_gen_count[mi]);
            uart_puts(" (expected 1)");
            errs = errs + 1;
        } else {
            uart_puts("  OK: 1 GEN block");
        }

        int lc_idx = mac_gen_lcount_idx(mi, 0);
        if (mac_gen_lcount[lc_idx] != 2) {
            uart_putstr("  FAIL: gen line count = ");
            print_int(mac_gen_lcount[lc_idx]);
            uart_puts(" (expected 2)");
            errs = errs + 1;
        } else {
            uart_puts("  OK: 2 GEN lines");
        }

        /* Verify GEN line content */
        int li0 = mac_gen_line_idx(mi, 0, 0);
        if (!str_eq(mac_gen_lines[li0], "mvi r0,{LENGTH}")) {
            uart_putstr("  FAIL: gen line 0 = '");
            uart_putstr(mac_gen_lines[li0]);
            uart_puts("'");
            errs = errs + 1;
        } else {
            uart_puts("  OK: gen line 0 = 'mvi r0,{LENGTH}'");
        }

        int li1 = mac_gen_line_idx(mi, 0, 1);
        if (!str_eq(mac_gen_lines[li1], "svc 10")) {
            uart_putstr("  FAIL: gen line 1 = '");
            uart_putstr(mac_gen_lines[li1]);
            uart_puts("'");
            errs = errs + 1;
        } else {
            uart_puts("  OK: gen line 1 = 'svc 10'");
        }

        mac_dump();
    }

    /* Test 2: Lookup by name */
    uart_puts("--- macrodef: lookup ---");
    if (mac_lookup("GETMAIN") != 0) {
        uart_puts("  FAIL: GETMAIN not found at index 0");
        errs = errs + 1;
    } else {
        uart_puts("  OK: GETMAIN found at index 0");
    }
    if (mac_lookup("NONEXIST") != -1) {
        uart_puts("  FAIL: NONEXIST should return -1");
        errs = errs + 1;
    } else {
        uart_puts("  OK: NONEXIST returns -1");
    }

    /* Test 3: Parse multiple macros from .msw file */
    uart_puts("--- macrodef: multi ---");
    mac_init();

    char *multi_src =
        "MACRODEF GETMAIN;"
        "   REQUIRED LENGTH(expr);"
        "   GEN DO;"
        "      'mvi r0,{LENGTH}';"
        "      'svc 10';"
        "   END;"
        "END;"
        "MACRODEF FREEMAIN;"
        "   REQUIRED ADDRESS(expr);"
        "   GEN DO;"
        "      'mvi r0,{ADDRESS}';"
        "      'svc 11';"
        "   END;"
        "END;";

    lex_init(multi_src, str_len(multi_src));
    lex_scan();
    int count = mac_parse_file();

    if (mac_parse_err) {
        uart_putstr("  PARSE ERROR: ");
        uart_puts(mac_parse_errmsg);
        errs = errs + 1;
    } else if (count != 2) {
        uart_putstr("  FAIL: parsed ");
        print_int(count);
        uart_puts(" macros (expected 2)");
        errs = errs + 1;
    } else {
        uart_puts("  OK: parsed 2 macros");
    }

    if (mac_lookup("GETMAIN") != 0) {
        uart_puts("  FAIL: GETMAIN not at index 0");
        errs = errs + 1;
    } else {
        uart_puts("  OK: GETMAIN at index 0");
    }
    if (mac_lookup("FREEMAIN") != 1) {
        uart_puts("  FAIL: FREEMAIN not at index 1");
        errs = errs + 1;
    } else {
        uart_puts("  OK: FREEMAIN at index 1");
    }

    mac_dump();

    /* Test 4: Macro with body (IF/THEN statements after GEN) */
    uart_puts("--- macrodef: body ---");
    mac_init();

    char *body_src =
        "MACRODEF GETMAIN;"
        "   REQUIRED LENGTH(expr);"
        "   OPTIONAL ADDRESS(lvalue);"
        "   GEN DO;"
        "      'mvi r0,{LENGTH}';"
        "      'svc 10';"
        "   END;"
        "   IF ADDRESS THEN DO;"
        "      ADDRESS = 0;"
        "   END;"
        "END;";

    lex_init(body_src, str_len(body_src));
    lex_scan();
    mi = mac_parse_def();

    if (mac_parse_err) {
        uart_putstr("  PARSE ERROR: ");
        uart_puts(mac_parse_errmsg);
        errs = errs + 1;
    } else {
        if (mac_body[mi][0] == 0) {
            uart_puts("  FAIL: body is empty");
            errs = errs + 1;
        } else {
            uart_putstr("  OK: body = '");
            uart_putstr(mac_body[mi]);
            uart_puts("'");
        }
        /* Verify body contains IF ADDRESS */
        if (!str_find(mac_body[mi], "IF")) {
            uart_puts("  FAIL: body missing IF");
            errs = errs + 1;
        } else {
            uart_puts("  OK: body contains IF");
        }
    }

    /* Test 5: label clause type */
    uart_puts("--- macrodef: label clause ---");
    mac_init();

