    uart_putstr("  PTR is_ptr: "); print_int(type_is_ptr(TYPE_PTR)); uart_putchar(10);
    uart_putstr("  INT24 is_ptr: "); print_int(type_is_ptr(TYPE_INT24)); uart_putchar(10);
