    emit_instr0("nop");
    emit_instr1("push", "fp");
    emit_instr2("mov", "fp", "sp");
    emit_instr("jmp     (r1)");
    uart_putstr(emit_output());

    /* Test 6: comments */
    uart_puts("--- comments ---");
    emit_init();
    emit_comment("PL/SW source line");
    emit_source_line("x = y + 1;");
    uart_putstr(emit_output());

    /* Test 7: section switching */
