    lex_init(label_src, str_len(label_src));
    lex_scan();
    mi = mac_parse_def();

    if (mac_parse_err) {
        uart_putstr("  PARSE ERROR: ");
        uart_puts(mac_parse_errmsg);
        errs = errs + 1;
    } else {
        int idx0 = mac_cl_idx(mi, 0);
        if (mac_cl_types[idx0] != MCLAUSE_LABEL) {
            uart_puts("  FAIL: TARGET type != label");
            errs = errs + 1;
        } else {
            uart_puts("  OK: TARGET(label)");
        }
        int idx1 = mac_cl_idx(mi, 1);
        if (mac_cl_types[idx1] != MCLAUSE_EXPR) {
            uart_puts("  FAIL: COND type != expr");
            errs = errs + 1;
        } else {
            uart_puts("  OK: COND(expr)");
        }
    }

    /* Summary */
    uart_putstr("macrodef parsing errors: ");
    print_int(errs);
    uart_putchar(10);
}

