    test_type_binop("and", TOK_AND, TYPE_INT24, TYPE_INT24, TYPE_INT24);
    test_type_binop("or", TOK_OR, TYPE_INT24, TYPE_INT24, TYPE_INT24);
    test_type_binop("bw and", TOK_AMP, TYPE_BYTE, TYPE_BYTE, TYPE_BYTE);
