    /* Test 1: Assign literal to automatic variable */
    uart_puts("--- asgn: auto var ---");
    arena_init();
    ast_init();
    sym_init();
    emit_init();
    cg_init();
    si = sym_insert("X", TYPE_INT24, 3, STOR_AUTO);
