        errs = errs + 1;
    } else {
        layout_globals(prog);
        cg_program_procs(prog);
        out = emit_output();
        uart_putstr(out);

        if (!str_find(out, "_MAIN:")) {
            uart_puts("  FAIL: missing proc label _MAIN");
