    if (ok == expect) {
        uart_puts(" OK");
    } else {
        uart_puts(" FAIL");
    }
}

void test_type_binop(char *label, int op, int lt, int rt, int expect) {
    uart_putstr("  ");
    uart_putstr(label);
    uart_putstr(": ");
    uart_putstr(nd_type_name(lt));
    uart_putstr(" ");
    uart_putstr(tok_name(op));
    uart_putstr(" ");
