    types_init();
    layout_init();
    emit_init();
    cg_init();
    cg_static_init();

    parse_init("PROC ABS(X INT(24)) RETURNS(INT(24)); IF X < 0 THEN RETURN(0 - X); ELSE RETURN(X); END;");
    prog = parse_program();
    if (parse_err) {
        uart_putstr("  PARSE ERROR: ");
        uart_puts(parse_errmsg);
        errs = errs + 1;
