/* Run a test suite by number. Returns 1 if valid suite. */
int run_suite(int n) {
    if (n == 0) { uart_puts("=== String Tests ==="); test_strings(); }
    else if (n == 1) { uart_puts("=== Arena Tests ==="); test_arena(); }
    else if (n == 2) { uart_puts("=== Token Tests ==="); test_tokens(); }
