    emit_named_label("main");
    emit_prologue();
    emit_epilogue();
    emit_data_section();
    emit_named_label("msg");
    emit_ascii("Hello");
    emit_zero();
    emit_text_section();
    emit_comment("back in text");
    uart_putstr(emit_output());

    /* Test 8: .globl directive */
